import { createContext, useContext, useEffect, useMemo, useState } from 'react';

const CartContext = createContext(null);

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);

  // 1. Tải giỏ hàng từ localStorage khi vừa vào web
  useEffect(() => {
    try {
      const savedCart = localStorage.getItem('cart');
      if (savedCart) setCart(JSON.parse(savedCart));
    } catch (error) {
      console.error('Lỗi đọc giỏ hàng:', error);
      localStorage.removeItem('cart');
    } finally {
      setLoading(false);
    }
  }, []);

  // 2. Hàm then chốt: Lưu state và kích hoạt đồng bộ real-time lập tức cho tất cả các trang
  const saveCartState = (newCart) => {
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
    window.dispatchEvent(new Event('storage')); // Ép các component khác vẽ lại ngay
  };

  const addToCart = (product) => {
    if (!product || !product.id) return;
    const existingProduct = cart.find((item) => item.id === product.id);
    const updatedCart = existingProduct
      ? cart.map((item) => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item)
      : [...cart, { ...product, quantity: 1 }];
    saveCartState(updatedCart);
  };

  const removeFromCart = (id) => {
    saveCartState(cart.filter((item) => item.id !== id));
  };

  const updateQuantity = (id, quantity) => {
    if (quantity <= 0) {
      removeFromCart(id);
      return;
    }
    saveCartState(cart.map((item) => item.id === id ? { ...item, quantity } : item));
  };

  const increaseQuantity = (id) => {
    saveCartState(cart.map((item) => item.id === id ? { ...item, quantity: item.quantity + 1 } : item));
  };

  const decreaseQuantity = (id) => {
    saveCartState(
      cart.map((item) => item.id === id ? { ...item, quantity: item.quantity - 1 } : item).filter((item) => item.quantity > 0)
    );
  };

  const clearCart = () => saveCartState([]);

  const cartTotal = useMemo(() => cart.reduce((total, item) => total + Number(item.price || 0) * item.quantity, 0), [cart]);
  const cartCount = useMemo(() => cart.reduce((total, item) => total + item.quantity, 0), [cart]);

  return (
    <CartContext.Provider value={{ cart, loading, addToCart, removeFromCart, updateQuantity, increaseQuantity, decreaseQuantity, clearCart, cartTotal, cartCount }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (!context) throw new Error('useCart phải được sử dụng bên trong CartProvider');
  return context;
};
